package ConditionalStatement_learn;

/**
 * 
 */
public class IfElseIfCondition {

	/**
	 * @param args
	 */
	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int color = 2;
		if(color == 1) {
			System.out.println("Color is blue");
		}
		else if(color == 2) {
			System.out.println("Sky blue");
		}
		else
			System.out.println("Navi blue");
	}	

}
